import{_ as e,c as t,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"플랫폼 기능: AI 할당량 조회 | opencode-mystatus","description":"opencode-mystatus의 플랫폼별 할당량 조회 기능을 학습합니다. OpenAI, 지푸 AI, GitHub Copilot, Google Cloud 4개 플랫폼을 지원합니다.","frontmatter":{"title":"플랫폼 기능: AI 할당량 조회 | opencode-mystatus","sidebarTitle":"플랫폼 기능","subtitle":"플랫폼 기능: AI 할당량 조회","description":"opencode-mystatus의 플랫폼별 할당량 조회 기능을 학습합니다. OpenAI, 지푸 AI, GitHub Copilot, Google Cloud 4개 플랫폼을 지원합니다.","order":2},"headers":[],"relativePath":"ko/vbgate/opencode-mystatus/platforms/index.md","filePath":"ko/vbgate/opencode-mystatus/platforms/index.md"}'),i={name:"ko/vbgate/opencode-mystatus/platforms/index.md"};function r(d,a,n,s,u,h){return o(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="플랫폼-기능" tabindex="-1">플랫폼 기능 <a class="header-anchor" href="#플랫폼-기능" aria-label="Permalink to &quot;플랫폼 기능&quot;">​</a></h1><p>이 장에서는 opencode-mystatus가 지원하는 각 AI 플랫폼의 할당량 조회 기능을 상세히 소개합니다.</p><h2 id="지원되는-플랫폼" tabindex="-1">지원되는 플랫폼 <a class="header-anchor" href="#지원되는-플랫폼" aria-label="Permalink to &quot;지원되는 플랫폼&quot;">​</a></h2><p>opencode-mystatus는 다음 4개의 주요 AI 플랫폼을 지원합니다:</p><table tabindex="0"><thead><tr><th>플랫폼</th><th>할당량 유형</th><th>특징</th></tr></thead><tbody><tr><td>OpenAI</td><td>3시간 / 24시간 슬라이딩 창</td><td>Plus, Team, Pro 구독 지원</td></tr><tr><td>지푸 AI</td><td>5시간 Token / MCP 월간 할당량</td><td>Coding Plan 지원</td></tr><tr><td>GitHub Copilot</td><td>월간 할당량</td><td>Premium Requests 사용량 표시</td></tr><tr><td>Google Cloud</td><td>모델별 독립 계산</td><td>다중 계정, 4개 모델 지원</td></tr></tbody></table><h2 id="플랫폼-상세-설명" tabindex="-1">플랫폼 상세 설명 <a class="header-anchor" href="#플랫폼-상세-설명" aria-label="Permalink to &quot;플랫폼 상세 설명&quot;">​</a></h2><h3 id="openai-할당량" tabindex="-1"><a href="./openai-usage/">OpenAI 할당량</a> <a class="header-anchor" href="#openai-할당량" aria-label="Permalink to &quot;[OpenAI 할당량](./openai-usage/)&quot;">​</a></h3><p>OpenAI 할당량 조회 메커니즘을 깊이 이해합니다:</p><ul><li>3시간 및 24시간 슬라이딩 창의 차이</li><li>팀 계정의 할당량 공유 메커니즘</li><li>JWT 토큰 파싱으로 계정 정보 얻기</li></ul><h3 id="지푸-ai-할당량" tabindex="-1"><a href="./zhipu-usage/">지푸 AI 할당량</a> <a class="header-anchor" href="#지푸-ai-할당량" aria-label="Permalink to &quot;[지푸 AI 할당량](./zhipu-usage/)&quot;">​</a></h3><p>지푸 AI 및 Z.ai 할당량 조회를 이해합니다:</p><ul><li>5시간 Token 할당량의 계산 방식</li><li>MCP 월간 할당량의 용도</li><li>API Key 마스킹 표시</li></ul><h3 id="github-copilot-할당량" tabindex="-1"><a href="./copilot-usage/">GitHub Copilot 할당량</a> <a class="header-anchor" href="#github-copilot-할당량" aria-label="Permalink to &quot;[GitHub Copilot 할당량](./copilot-usage/)&quot;">​</a></h3><p>GitHub Copilot 할당량 관리를 마스터합니다:</p><ul><li>Premium Requests의 의미</li><li>다른 구독 유형의 할당량 차이</li><li>월간 재설정 시간 계산</li></ul><h3 id="google-cloud-할당량" tabindex="-1"><a href="./google-usage/">Google Cloud 할당량</a> <a class="header-anchor" href="#google-cloud-할당량" aria-label="Permalink to &quot;[Google Cloud 할당량](./google-usage/)&quot;">​</a></h3><p>Google Cloud 다중 계정 할당량 조회를 학습합니다:</p><ul><li>4개 모델(G3 Pro, G3 Image, G3 Flash, Claude)의 차이</li><li>다중 계정 관리 및 전환</li><li>인증 파일 읽기 메커니즘</li></ul><h2 id="선택-가이드" tabindex="-1">선택 가이드 <a class="header-anchor" href="#선택-가이드" aria-label="Permalink to &quot;선택 가이드&quot;">​</a></h2><p>사용하는 플랫폼에 따라 해당 튜토리얼을 선택하세요:</p><ul><li><strong>OpenAI만 사용</strong>: 바로 <a href="./openai-usage/">OpenAI 할당량</a> 보기</li><li><strong>지푸 AI만 사용</strong>: 바로 <a href="./zhipu-usage/">지푸 AI 할당량</a> 보기</li><li><strong>다중 플랫폼 사용자</strong>: 모든 플랫폼 튜토리얼을 순서대로 읽는 것이 좋습니다</li><li><strong>Google Cloud 사용자</strong>: 먼저 <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> 플러그인 설치 필요</li></ul><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 완료하면 <a href="./../advanced/">고급 기능</a>을 계속 학습하여 더 많은 설정 옵션을 이해할 수 있습니다.</p>',23)])])}const g=e(i,[["render",r]]);export{c as __pageData,g as default};
